/**
 * antiqueue: Load Topology Instrumentation (Rust)
 *
 * LAYER 1: Queue operations are correct ✓
 * LAYER 2: Handles normal burst loads ✓
 * LAYER 3: BREAKS under sustained high load (queue_depth > 10K) ✗
 *
 * Prevention strategy:
 * 1. Queue depth monitoring
 * 2. Backpressure rejection (fail fast, don't buffer)
 * 3. Priority shedding (drop low-priority items)
 */

use std::collections::VecDeque;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;

#[derive(Debug, Clone, PartialEq)]
pub enum Priority {
    Low,
    Medium,
    High,
    Critical,
}

#[derive(Debug, Clone)]
pub struct WorkItem {
    pub id: usize,
    pub priority: Priority,
    pub payload: String,
}

pub struct LoadMeasurement {
    pub queue_depth: usize,
    pub depth_threshold: usize,
    pub is_critical: bool,
    pub strategy: BackpressureStrategy,
    pub shedding_rate: f64,
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub enum BackpressureStrategy {
    Accept,         // Queue has space
    Pressure,       // Approaching threshold (warning level)
    Reject,         // Queue full - reject new items
    ShedLowPriority, // Queue critical - shed lowest priority
}

pub struct AntiQueueLoadMetrics {
    queue: VecDeque<WorkItem>,
    depth_threshold: usize,            // 10,000 items
    critical_threshold: usize,         // 12,000 items (hard limit)
    items_shed: Arc<AtomicUsize>,
    items_rejected: Arc<AtomicUsize>,
}

impl AntiQueueLoadMetrics {
    pub fn new() -> Self {
        Self {
            queue: VecDeque::new(),
            depth_threshold: 10000,
            critical_threshold: 12000,
            items_shed: Arc::new(AtomicUsize::new(0)),
            items_rejected: Arc::new(AtomicUsize::new(0)),
        }
    }

    /**
     * MEASURE: Queue depth and health
     */
    pub fn measure_load(&self) -> LoadMeasurement {
        let depth = self.queue.len();
        let is_critical = depth > self.depth_threshold;

        let strategy = if depth > self.critical_threshold {
            BackpressureStrategy::ShedLowPriority
        } else if depth > self.depth_threshold {
            BackpressureStrategy::Reject
        } else if depth > self.depth_threshold / 2 {
            BackpressureStrategy::Pressure
        } else {
            BackpressureStrategy::Accept
        };

        let shedding_rate = if self.items_shed.load(Ordering::Relaxed) == 0 {
            0.0
        } else {
            (self.items_shed.load(Ordering::Relaxed) as f64
                / (depth as f64 + 1.0))
                * 100.0
        };

        LoadMeasurement {
            queue_depth: depth,
            depth_threshold: self.depth_threshold,
            is_critical,
            strategy,
            shedding_rate,
        }
    }

    /**
     * ENQUEUE: With backpressure
     */
    pub fn enqueue_with_load(&mut self, item: WorkItem) -> Result<(), WorkItem> {
        let load = self.measure_load();

        match load.strategy {
            BackpressureStrategy::Accept => {
                // Normal case: queue has space
                self.queue.push_back(item);
                Ok(())
            }
            BackpressureStrategy::Pressure => {
                // Warning: approaching threshold
                eprintln!(
                    "WARNING: Queue depth {} approaching threshold {}",
                    load.queue_depth, load.depth_threshold
                );
                self.queue.push_back(item);
                Ok(())
            }
            BackpressureStrategy::Reject => {
                // CRITICAL: Queue full - reject
                eprintln!(
                    "CRITICAL: Queue depth {} exceeds threshold {} at Layer 3 - rejecting",
                    load.queue_depth, load.depth_threshold
                );
                self.items_rejected.fetch_add(1, Ordering::Relaxed);
                Err(item)
            }
            BackpressureStrategy::ShedLowPriority => {
                // CRITICAL: Shed low-priority items
                eprintln!(
                    "CRITICAL: Queue depth {} exceeds critical threshold {} - shedding low priority",
                    load.queue_depth, self.critical_threshold
                );
                self.shed_low_priority();
                self.queue.push_back(item);
                Ok(())
            }
        }
    }

    /**
     * DEGRADATION: Shed low-priority items
     */
    fn shed_low_priority(&mut self) {
        let to_remove = (self.queue.len() / 10).max(1);
        let mut shed_count = 0;

        eprintln!("DEGRADATION: Shedding {} items", to_remove);

        for _ in 0..to_remove {
            if let Some(item) = self.queue.pop_front() {
                if item.priority == Priority::Low {
                    // Shed it (drop on floor)
                    eprintln!("Shed: {} (low priority)", item.id);
                    self.items_shed.fetch_add(1, Ordering::Relaxed);
                    shed_count += 1;
                } else {
                    // Put it back (re-queue)
                    self.queue.push_front(item);
                }
            }
        }

        eprintln!("Shed {} items successfully", shed_count);
    }

    /**
     * DEQUEUE: With monitoring
     */
    pub fn dequeue(&mut self) -> Option<WorkItem> {
        let load = self.measure_load();

        if load.is_critical {
            eprintln!(
                "WARNING: Dequeueing with critical queue depth {}",
                load.queue_depth
            );
        }

        self.queue.pop_front()
    }

    /**
     * STATE: Get metrics
     */
    pub fn get_load_state(&self) -> LoadMeasurement {
        self.measure_load()
    }

    /**
     * STATS: Monitoring
     */
    pub fn get_stats(&self) -> (usize, usize) {
        (
            self.items_shed.load(Ordering::Relaxed),
            self.items_rejected.load(Ordering::Relaxed),
        )
    }
}

/**
 * MONITORING: Export metrics
 */
pub fn export_antiqueue_metrics(queue: &AntiQueueLoadMetrics) -> String {
    let load = queue.get_load_state();
    let (shed, rejected) = queue.get_stats();

    format!(
        r#"{{
  "system": "antiqueue Backpressure",
  "layer": {},
  "metrics": {{
    "queue_depth": {},
    "depth_threshold": {},
    "strategy": "{:?}",
    "shedding_rate": {:.2}%,
    "items_shed": {},
    "items_rejected": {},
    "critical": {}
  }}
}}"#,
        if load.is_critical {
            3
        } else if load.queue_depth > 5000 {
            "2.5"
        } else {
            "2"
        },
        load.queue_depth,
        load.depth_threshold,
        load.strategy,
        load.shedding_rate,
        shed,
        rejected,
        load.is_critical
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_accept_on_normal_load() {
        let mut queue = AntiQueueLoadMetrics::new();

        let item = WorkItem {
            id: 1,
            priority: Priority::High,
            payload: "test".to_string(),
        };

        let result = queue.enqueue_with_load(item.clone());
        assert!(result.is_ok());
        assert_eq!(queue.queue.len(), 1);
    }

    #[test]
    fn test_reject_on_threshold_exceeded() {
        let mut queue = AntiQueueLoadMetrics::new();

        // Fill past threshold
        for i in 0..10001 {
            let item = WorkItem {
                id: i,
                priority: Priority::Low,
                payload: "test".to_string(),
            };
            let _ = queue.enqueue_with_load(item);
        }

        let overload = WorkItem {
            id: 10001,
            priority: Priority::High,
            payload: "test".to_string(),
        };

        let result = queue.enqueue_with_load(overload);
        assert!(result.is_err());
    }

    #[test]
    fn test_pressure_warning() {
        let mut queue = AntiQueueLoadMetrics::new();

        // Fill to warning level
        for i in 0..5000 {
            let item = WorkItem {
                id: i,
                priority: Priority::Low,
                payload: "test".to_string(),
            };
            queue.queue.push_back(item);
        }

        let load = queue.measure_load();
        assert_eq!(load.strategy, BackpressureStrategy::Pressure);
    }

    #[test]
    fn test_shedding_on_critical() {
        let mut queue = AntiQueueLoadMetrics::new();

        // Fill past critical
        for i in 0..12001 {
            let item = WorkItem {
                id: i,
                priority: Priority::Low,
                payload: "test".to_string(),
            };
            queue.queue.push_back(item);
        }

        let initial_depth = queue.queue.len();
        queue.shed_low_priority();
        let final_depth = queue.queue.len();

        assert!(final_depth < initial_depth);
    }
}
